class Solution {
public:
    int removeDuplicates(int* nums, int n) {
        if (n <= 1) return n;
        int i = 1;
        for (int j = 1; j < n; j++) {
            if (nums[j] != nums[i-1]) nums[i] = nums[j];
            i++;
        }
        return i;
    }
};
int main() {
    std::cin >> n;
    for (int i = 0; i < n; i++) {
        int x;
        std::cin >> x;
        nums[i] = x;
    }
    Solution sol;
    int ans = sol.removeDuplicates(nums, n);
    std::cout << ans << std::endl;
    return 0;
}
